module freq_div
(
    input CLK_in,
    input RST,
    output CLK_50,
    output CLK_10,
    output CLK_1
);

reg [3:0] cnt_50 = 0;
reg [3:0] cnt_10 = 0;
reg [6:0] cnt_1 = 0;
reg clk_50 = 0;
reg clk_10 = 0;
reg clk_1 = 0;

always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
        cnt_50 <= 0;
        cnt_10 <= 0;
        cnt_1 <= 0;
        clk_50 <= 0;
        clk_10 <= 0;
        clk_1 <= 0;
    end
    else begin
        // CLK_50 generation
        clk_50 <= ~clk_50;
        cnt_50 <= cnt_50 + 1;
        if (cnt_50 == 4) begin
            clk_50 <= ~clk_50;
            cnt_50 <= 0;
        end

        // CLK_10 generation
        clk_10 <= ~clk_10;
        cnt_10 <= cnt_10 + 1;
        if (cnt_10 == 4) begin
            clk_10 <= ~clk_10;
            cnt_10 <= 0;
        end

        // CLK_1 generation
        clk_1 <= ~clk_1;
        cnt_1 <= cnt_1 + 1;
        if (cnt_1 == 49) begin
            clk_1 <= ~clk_1;
            cnt_1 <= 0;
        end
    end
end

assign CLK_50 = clk_50;
assign CLK_10 = clk_10;
assign CLK_1 = clk_1;

endmodule
